openscad:
$fn = 60;
case_diameter = 40; // [30:1:60]
case_height = 8; // [5:15]
case_thickness = 3; // [1:0.5:6]
dial_thickness = 1.5; // [0.5:0.5:3]
hand_width = 1.2; // [0.8:0.2:2.5]
hour_length = 15; // [10:1:25]
minute_length = 20; // [12:1:30]
second_length = 25; // [15:1:35]
hour_angle = 30; // [0:6:360]
minute_angle = 120; // [0:6:360]
second_angle = 240; // [0:6:360]

module watch_case() {
    color([0.9, 0.95, 1, 0.3])
    difference() {
        cylinder(d=case_diameter, h=case_height);
        translate([0,0,case_thickness])
            cylinder(d=case_diameter-case_thickness*2, h=case_height);
        translate([0,0,-0.1])
            cylinder(d=case_diameter-case_thickness*1.5, h=case_thickness+0.2);
    }
}

module dial() {
    color("black")
    cylinder(d=case_diameter-case_thickness*2.5, h=dial_thickness);
}

module hand(length, width, angle) {
    color("white")
    rotate([0,0,angle])
    translate([0, -width/2, dial_thickness+0.1])
        cube([length, width, 0.8]);
}

watch_case();
translate([0,0,case_thickness])
    dial();
hand(hour_length, hand_width*1.3, hour_angle);
hand(minute_length, hand_width, minute_angle);
hand(second_length, hand_width*0.6, second_angle);
